import React from "react";
import styles from "./cart-item.module.css";
import CartLayout from "../../layout/cart-layout";
import Title from "../../title";
import ButtonDelete from "../../button-delete";
import Quantity from "../../product-details/quantity"; // Import the Quantity component
import { useAppSelector, useDispatch } from "../../../app/hooks";
import { RootState } from "../../../app/store";


interface CartProps {
  product: {
    id: number;
    img: string;
    name: string;
    price: number;
  };
}

const CartItem: React.FC<CartProps> = ({ product }) => {
  // Retrieve the quantity from the Redux store using useAppSelector
  const quantity = useAppSelector((state: RootState) =>
    (state.cart.items.find((item) => item.id === product.id)?.quantity) ?? 0
  );

  // Callback function to update the quantity in the Redux store
  const dispatch = useDispatch();
  const handleQuantityChange = (newQuantity: number) => {
    // Dispatch an action to update the quantity in the Redux store
    dispatch(updateQuantity({ id: product.id, quantity: newQuantity }));
  };

  return (
    <>
      <div className={styles.wrapper_cart_item}>
        <CartLayout>
          <div className={`${styles.cart_product} ${styles.right_aligned}`}>
            <div className={styles.wrapper_image}>
              <img src={product.img} alt="candle" width={160} height={120} />
            </div>
            <div className={styles.cart_info}>
              <Title level="h3" className={styles.item_title}>
                {product.name}
              </Title>
              {/* Include the 'product' prop when calling 'ButtonDelete' */}
              <ButtonDelete productId={product.id} />
            </div>
          </div>
          <div className={`${styles.cart_price} ${styles.right_aligned}`}>
            $ {product.price}
          </div>
          <div className={styles.cart_quantity}>
            {/* Use the Quantity component and pass the itemId, quantity, and onQuantityChange */}
            <Quantity
              itemId={product.id}
              quantity={quantity}
              onQuantityChange={handleQuantityChange}
            />
          </div>
          <div className={`${styles.cart_total} ${styles.right_aligned}`}>
            {/* Calculate and display the total price based on the retrieved quantity and price */}
            $ {product.price * quantity}
          </div>
        </CartLayout>
      </div>
      <div className={styles.divider} />
    </>
  );
};

export default CartItem;









